class Node:
    def __init__(self, char):
        self.char = char.lower()
        self.left = None
        self.right = None

class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = Node(char)
        else:
            self._insert_recursive(self.root, char)

    def _insert_recursive(self, node, char):
        if char < node.char:
            if node.left is None:
                node.left = Node(char)
            else:
                self._insert_recursive(node.left, char)
        elif char > node.char:
            if node.right is None:
                node.right = Node(char)
            else:
                self._insert_recursive(node.right, char)

def process_string(s, index=0, bst=None):
    if bst is None:
        bst = BinarySearchTree()
    if index >= len(s):
        return bst
    char = s[index]
    if not hasattr(bst, 'seen_chars'):
        bst.seen_chars = set()
    if char.lower() not in bst.seen_chars:
        bst.seen_chars.add(char.lower())
        bst.insert(char.lower())
    return process_string(s, index + 1, bst)

